insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'aichi' and m.slug = 'nagoya'), 'aichi-nagoya-postpartum-care', '名古屋市産後ケア事業（なごやMommy Care⁺）', '名古屋市が実施する産後ケア事業「なごやMommy Care⁺」。出産後の母親と乳児を対象に、心身のケアや育児のサポートを、施設に宿泊する「宿泊型」、施設に通う「通所型」、自宅で受ける「訪問型」の3つの形で提供します。令和7年10月1日利用分から利用要件・利用料金が見直され、現行の「なごやMommy Care⁺」となりました。妊娠32週以降から名古屋市電子申請システムで利用申込ができるとされていますが、対象者の詳細な要件（母親の状態や育児不安の有無など）は公式ページ本文には明記されておらず、案内チラシ等で確認する必要があります。利用可能な児の月齢は事業所・サービスごとに異なるとされています。産前・産後ヘルプ事業（家事支援のヘルパー派遣）とは別の事業として案内されています。', '出産のあと、お母さんと赤ちゃんが心と体のケアや育児のサポートを受けられる名古屋市の制度です。泊まる「宿泊型」、日帰りで通う「通所型」、自宅に来てもらう「訪問型」があります。妊娠32週ごろからオンラインで申し込めるとされていますが、詳しい対象条件は名古屋市の窓口やチラシで確認してください。', 'service', '出産後の名古屋市在住の母親と乳児が対象となる可能性がありますが、公式ページ本文には育児不安等の詳しい対象要件は明記されていません。利用申込時点で妊娠32週以降であることが必要とされています。受け入れ可能な乳児の月齢は事業所・サービスごとに異なるとされているため、詳細は公式チラシまたは子育て支援課で確認してください。', '1日あたりの利用料（階層区分により変動）：生活保護受給世帯または両親とも市民税非課税の世帯は宿泊型・通所型・訪問型いずれも0円。それ以外の世帯は宿泊型3,520円、通所型2,360円、訪問型1,560円とされています。キャンセル料は階層区分にかかわらず同額発生するとされています。1回の出産につき利用上限は最大7日分（令和7年10月の制度改正前後の利用分を通算）とされています。', '妊娠32週以降から名古屋市電子申請システムで利用申込ができるとされています。申請から利用決定まで2〜3週間程度かかるとされているため、早めの申請が推奨されます。具体的な期限は公式ページで確認してください。', '名古屋市電子申請システムでオンライン申込ができるとされています。申込受付後、名古屋市子ども青少年局子育て支援課から「名古屋市産後ケア事業利用承認決定通知書」と「利用券」が自宅へ郵送されるとされています。', '母子健康手帳、利用券（承認後に郵送されるもの）が必要とされています。そのほかの必要書類は公式ページまたは子育て支援課で確認してください。', TRUE, '名古屋市子ども青少年局子育て支援部子育て支援課母子保健担当', '052-972-2629', NULL, 'https://www.city.nagoya.jp/kodomo/ninshin/1008971/1008978.html', '名古屋市産後ケア事業｜名古屋市公式ウェブサイト', '2026-07-01', 'medium', ARRAY['targetPeople', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本内容は確認日時点の名古屋市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。特に対象者の詳細要件は公式ページ本文に明記されていないため、案内チラシまたは子育て支援課への確認を強くおすすめします。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
