insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei postpartum-care import', '{"slug":"aichi-nagoya-postpartum-care","status":"review","title":"名古屋市産後ケア事業（なごやMommy Care⁺）","officialUrl":"https://www.city.nagoya.jp/kodomo/ninshin/1008971/1008978.html","topic":"postpartum-care"}'::jsonb, 'seirei:aichi-nagoya-postpartum-care:YWljaGktbmFnb3lhLXBvc3RwYXJ0dW0tY2FyZXw0aVcvSS9oRlJQVWlBQm1FSDg1M3hMVGc=' from public.support_programs sp where sp.slug='aichi-nagoya-postpartum-care' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'chiba' and m.slug = 'chiba'), 'chiba-chiba-postpartum-care', '産後ケア事業（宿泊型・訪問型・日帰り型）', '千葉市が実施する産後ケア事業。出産後のお母さんと赤ちゃんを対象に、助産師等による心身のケアや育児指導等を、産科医療機関や助産所等に宿泊する「宿泊型」、助産師が自宅を訪問する「訪問型」、産科医療機関等を日帰りで利用する「日帰り型」の形で提供します。市内在住の方が対象となる可能性があり、宿泊型・日帰り型は産後5か月未満、訪問型は産後1年未満のお母さんと赤ちゃんが目安とされています（在胎37週未満の場合は延長の場合があるとされています）。利用料は世帯の課税状況に応じた自己負担割合（課税世帯10%、非課税世帯5%等）で算定される仕組みとされ、令和7年10月から一部制度が変更されています。出産予定日の3か月前から申請可能で、妊娠中の申請が勧められています。正確な料金・条件は公式ページで確認してください。', '出産のあと、お母さんと赤ちゃんが助産師さんから体と心のケアや育児の相談を受けられる千葉市の制度です。施設に泊まる「宿泊型」、自宅に来てもらう「訪問型」、日帰りで通う「日帰り型」から選べます。千葉市に住んでいる方が対象になる可能性があり、料金は世帯の状況によって変わります。出産予定日の3か月前から申し込めるとされています。', 'service', '千葉市内在住の方が対象となる可能性があります。宿泊型・日帰り型は産後5か月未満、訪問型は産後1年未満のお母さんと赤ちゃんが目安とされていますが、在胎37週未満の場合は利用可能期間が延長される場合があるとされています。正確な条件は公式ページで確認してください。', '利用料の上限額は宿泊型28,000円/日、訪問型11,000円/回、日帰り型20,000円/回とされ、自己負担割合は課税世帯10%、非課税世帯5%、生活保護世帯は宿泊型300円/日・訪問型無料・日帰り型300円/回とされています。令和7年10月から自己負担額や多胎児の利用上限回数（7日→10日）が変更されているとされています。正確な金額は公式ページで確認してください。', '出産予定日の3か月前から申請可能で、妊娠中の申請が推奨されているとされています。具体的な締切等は公式ページで確認してください。', '窓口での申請が基本とされ、面接方法としてZoomによるオンライン面接も選択できるとされています。オンライン申請専用システムの明記は確認できませんでした。', '母子健康手帳、応援プラン、印鑑、千葉市産後ケア事業登録兼利用申請書が必要とされ、必要に応じて所得証明書等の提出を求められる場合があるとされています。詳細は公式ページで確認してください。', FALSE, '千葉市保健福祉局健康福祉部健康支援課（各区母子健康包括支援担当）', '043-238-9925', NULL, 'https://www.city.chiba.jp/hokenfukushi/kenkofukushi/shien/29sangokea.html', '千葉市：産後ケア事業', '2026-07-01', 'high', ARRAY['onlineApplicationAvailable']::text[], '本内容は確認日時点の千葉市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
