insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'fukuoka' and m.slug = 'fukuoka'), 'fukuoka-fukuoka-postpartum-care', '福岡市産後ケア事業', '福岡市が母子保健法に基づき実施する産後ケア事業。出産後のお母さんと赤ちゃん、または流産・死産を経験して1年未満の女性を対象に、医療機関や助産所等で助産師などによる授乳・沐浴のアドバイス、育児相談、お母さんの体調管理などのケアを、施設に宿泊する「宿泊型」、日中に施設に通う「日帰り型」、自宅で受ける「訪問型」の3つの形で提供します。福岡市内に住民票があり、赤ちゃん・お母さん共に医療行為の必要がない方が対象となる可能性があります。利用料・利用日数の上限・減免の条件などは公式ページで確認してください。', '出産のあと、お母さんと赤ちゃんが助産師さんなどから体と心のケアや授乳・育児の相談を受けられる福岡市の制度です。施設に泊まる「宿泊型」、日帰りで通う「日帰り型」、自宅に来てもらう「訪問型」から選べます。福岡市に住んでいる方が対象になる可能性があり、料金や日数などは市の窓口で確認してください。', 'service', '福岡市内に住民票があり、生後1年未満の赤ちゃんとその母親、または流産・死産を経験して1年未満の女性（妊婦を除く）で、かつ赤ちゃん・母親共に医療行為の必要がない方が対象となる可能性があります。詳細な該当要件は公式ページで確認してください。', '自己負担額の目安として、宿泊型は1日3,000円（1泊2日で6,000円）、日帰り型は1日2,000円、訪問型は1日（2〜3時間）500円とされています。宿泊型・日帰り型・訪問型を合わせて7日間までとされています。生活保護世帯・市民税非課税世帯は自己負担額が免除される場合があるとされています。最新の金額・条件は公式ページで確認してください。', NULL, '利用を希望する事業者へ直接連絡し、見学や利用時期について相談したうえで、利用申込書を提出して予約する流れとされています。利用証明書の交付を受け、利用時に証明書と母子健康手帳を提示する形とされています。詳細な手順は公式ページまたは窓口で確認してください。', '福岡市産後ケア事業利用申込書。減免を希望する場合は、生活保護受給証明書または市民税非課税証明書が必要となる可能性があります。詳細は公式ページで確認してください。', FALSE, '福岡市こども未来局こども健やか部こども健やか課', '092-711-4065', NULL, 'https://www.city.fukuoka.lg.jp/kodomo-mirai/k-sukoyaka/child/sangokea.html', '福岡市産後ケア事業のご案内', '2026-07-01', 'high', ARRAY['applicationDeadlineText', 'requiredDocumentsText（減免以外の追加書類の有無）', '利用可能な施設・事業者の詳細']::text[], '本内容は確認日時点の福岡市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
