insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'fukuoka' and m.slug = 'kitakyushu'), 'fukuoka-kitakyushu-postpartum-care', '産後ケア事業（宿泊型・通所型・居宅訪問型）', '北九州市が母子保健法に基づき実施する産後ケア事業。助産師等の看護職が中心となり、産後に育児等の支援が必要な母子を対象に、授乳や沐浴のアドバイス、育児相談、体調管理、母乳ケアなどを、施設に宿泊する「宿泊型」、施設に日帰りで通う「通所型」（短時間区分あり）、自宅で受ける「居宅訪問型」の形で提供します。北九州市内に住所があり、出産後1年を経過していない、医療行為を必要としない母子で、産後ケアを必要とする方が対象となる可能性があります。利用料は一般世帯・減免世帯で異なり、利用日数は通算で最大7日までとされていますが、詳細な条件や利用可能な事業所は公式ページで確認してください。', '出産後1年未満のお母さんと赤ちゃんが、助産師さんなどから体のケアや育児の相談を受けられる北九州市の制度です。施設に泊まる、日帰りで通う、自宅に来てもらうの3つから選べる可能性があります。料金や日数などは市の窓口で確認してください。', 'service', '北九州市内に住所があり、出産後1年を経過していないお母さんと赤ちゃんで、医療行為を必要とせず、産後ケアを必要とする方が対象となる可能性があります（母子ともに感染症状がないことが条件とされています）。詳しい要件は公式ページで確認してください。', '1日あたりの自己負担額（食事代込み）は、宿泊型が一般世帯3,000円・減免世帯1,000円、通所型が一般世帯1,000円・減免世帯300円、通所型（短時間）が一般世帯500円・減免世帯150円、居宅訪問型が一般世帯1,000円・減免世帯300円とされています。生活保護世帯・市民税非課税世帯等は減免対象となる可能性があります。多胎児の場合も自己負担額は変わらないとされています。最新の金額は公式ページで確認してください。', '市内の事業所を利用する場合の明確な期限の記載は確認できませんでした。市外の産後ケア施設を利用する場合は、利用する2週間前までの申請が必要とされています。詳細は公式ページまたは窓口で確認してください。', '利用を希望する事業所へ連絡し、利用や日程調整について相談します。利用が決まった後、事業所へ「産後ケア事業登録利用申請書」を提出する流れとされています。市外の産後ケア施設を利用する場合はオンライン申請の案内があります。詳しい手順は公式ページで確認してください。', '産後ケア事業登録利用申請書（市内利用は様式第1号、市外施設利用は様式1-1号）、利用時に提示する母子健康手帳が必要とされています。利用料の減免を希望する場合は、生活保護受給証明書の写しまたは市民税非課税証明書の写しが必要となる可能性があります。', FALSE, '北九州市子ども家庭局子育て支援課', '093-582-2082', NULL, 'https://www.city.kitakyushu.lg.jp/contents/11700307.html', '産後のお母さんを支援します（産後ケア事業）- 北九州市', '2026-07-01', 'high', ARRAY['applicationDeadlineText（市内事業所利用時の申請期限の明記が本文で確認できなかったため）', '利用可能な具体的な事業所・実施施設の一覧', 'onlineApplicationAvailable']::text[], '本内容は確認日時点の北九州市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
