insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hiroshima' and m.slug = 'hiroshima'), 'hiroshima-hiroshima-postpartum-care', '広島市産後ケア事業（宿泊型・通所型・訪問型）', '広島市が実施する産後ケア事業。安心して子育てができるよう、助産師による自宅への訪問や、産科医療機関・助産所への宿泊・通所を通じて、出産後のお母さんの心身のケアや育児サポートなどの支援を行います。サービスは「宿泊型」（1泊2日から）、「通所型」（1日または短時間利用）、「訪問型」（自宅への訪問、1時間程度）の3つの形態から選べます。広島市に住所があり、産後1年未満で産後ケアを必要とするお母さんとお子様が対象となる可能性がありますが、感染性疾患がある方や入院加療・医療的介入が必要な方は対象外となる場合があります。利用料金や自己負担、補助の有無、申請時期などの詳細は、公式ページおよび各区地域支えあい課で確認してください。', '出産のあと、助産師さんが家に来てくれたり、施設に泊まったり日帰りで通ったりして、お母さんと赤ちゃんの体と心のケア・育児の相談ができる広島市の制度です。広島市に住み、産後1年未満の方が対象になる可能性があります。料金や申し込み時期は区の窓口で確認してください。', 'service', '広島市に住所を有し、産後1年未満のお母さんとお子様で、産後ケアを必要とする方が対象となる可能性があります。ただし、はしか・風しん・インフルエンザ等の感染性疾患に罹患している方、入院加療が必要な母親、精神疾患等により医療的介入が必要な母親（医師が産後ケア事業での対応が適切と判断した場合を除く）は対象外となる場合があります。流産・死産から1年未満の方も対象となる可能性があります。詳細な要件は公式ページで確認してください。', '課税世帯の場合、宿泊型が1泊2日11,136円、通所型が1日3,409円、訪問型が1回2,200円とされていますが、非課税世帯は無料となる可能性があります。また、令和8年度（令和9年3月31日まで）は利用料金の半額を補助するとされています。具体的な自己負担額は世帯状況等により異なる可能性があるため、公式ページおよび窓口で確認してください。', '通年で申請を受け付けているとみられますが、宿泊型・通所型は妊娠8か月（28週）ごろから、訪問型は出産後から申請可能とされています。具体的な期限の定めがあるかは公式ページで確認してください。', '広島市電子申請システムからのオンライン申請、または各区地域支えあい課（こども家庭センター）の窓口での申請が可能とされています。宿泊型・通所型は申請後に決定通知を受け取り、利用者自身で希望する事業者（施設）へ直接予約する流れとされています。訪問型は申請後、区の地域支えあい課から連絡がある流れとされています。', '申請書のほか、該当者は所得を証明する書類（生活保護世帯は被保護者証明書、市民税・県民税非課税世帯は課税台帳記載事項証明書等）が必要となる可能性があります。詳細は公式ページおよび窓口で確認してください。', TRUE, '各区地域支えあい課（こども家庭センター）', '082-504-2109', NULL, 'https://www.city.hiroshima.lg.jp/living/kosodate/1021253/1025913/1023754.html', '広島市産後ケア事業（宿泊型・通所型・訪問型）｜広島市公式ウェブサイト', '2026-07-01', 'high', ARRAY['benefitAmountText（区・年度・世帯区分による変動可能性、半額補助の具体的な適用条件）', 'applicationDeadlineText', 'contactPhone（区によって窓口電話番号が異なるため中区の番号を代表として記載）', 'requiredDocumentsText']::text[], '本内容は確認日時点の広島市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
