insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hokkaido' and m.slug = 'sapporo'), 'hokkaido-sapporo-postpartum-care', '産後ケア事業（宿泊型・日帰り型・訪問型）', '札幌市が実施する産後ケア事業。出産後のお母さんと赤ちゃんを対象に、育児のアドバイス（授乳・沐浴・寝かしつけ・夜泣きなど）や乳房のケア、お母さんが休息をとれるようにするための支援を、施設に宿泊する「宿泊型」（生後6か月未満）、施設に日帰りで通う「日帰り型」（生後1年未満）、自宅で助産師等の訪問を受ける「訪問型」（生後1年未満）の3つの形で提供します。札幌市に住民登録がある方が対象となる可能性がありますが、お母さんに医療的な介入が必要な場合など対象外となるケースもあるとされています。利用料は課税世帯と非課税・生活保護世帯で異なり、宿泊型は1泊7,500円（非課税等2,500円）、日帰り型は1日2,500円（同1,000円）、訪問型は1回2,500円（同1,000円）とされています。利用回数の上限や施設ごとの受入条件など、詳細は公式ページで確認してください。', '出産のあと、お母さんと赤ちゃんが育児のアドバイスや体のケアを受けられる札幌市の制度です。施設に泊まる「宿泊型」、日帰りで通う「日帰り型」、自宅に来てもらう「訪問型」から選べます。札幌市に住んでいる方が対象になる可能性があり、料金は世帯の状況によって変わります。「テオテ産後ケア」というオンラインサービスで申し込みます。', 'service', '札幌市に住民登録がある赤ちゃんとそのお母さんが対象となる可能性があります。ただし、お母さんに心身の不調や疾患があり医療的な介入が必要な場合などは対象外とされる場合があります。宿泊型は生後6か月未満、日帰り型・訪問型は生後1年未満が目安とされています。詳細な条件は公式ページで確認してください。', '課税世帯：宿泊型1泊7,500円、日帰り型1日2,500円、訪問型1回2,500円。非課税世帯・生活保護世帯：宿泊型1泊2,500円、日帰り型1日1,000円、訪問型1回1,000円とされています。利用回数の上限は宿泊型・日帰り型合わせて7日以内、訪問型は6回以内とされています。正確な金額・減免条件は公式ページで確認してください。', '妊娠28週から申請が可能とされています。利用予約は希望日の30日前から可能で、妊娠中の予約はできないとされています。具体的な締切等は公式ページで確認してください。', '「テオテ産後ケア」というオンラインサービスでアカウントを作成し、妊娠・出産情報を入力して札幌市へ申請するとされています。承認通知（メール）を受け取った後、利用したい施設を登録・予約する流れとされています。', '公式ページ本文には必要書類の一覧が明記されていませんでした。申請時にオンラインシステム上で入力が必要な情報（母子の情報等）があるとみられます。詳細は公式ページまたは窓口で確認してください。', TRUE, '札幌市子ども未来局子育て支援部子育て支援課母子保健係', '011-211-2785', NULL, 'https://kosodate.city.sapporo.jp/mokuteki/kenko/shussan/1002.html', '札幌市産後ケア事業 - さっぽろ子育て情報サイト', '2026-07-01', 'high', ARRAY['requiredDocumentsText']::text[], '本内容は確認日時点の札幌市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
