insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hyogo' and m.slug = 'kobe'), 'hyogo-kobe-postpartum-care', '神戸市産後ケア事業（宿泊・通所・訪問型）', '神戸市が実施する産後ケア事業。神戸市に住所があり、産後1年以内（子どもの1歳の誕生日の前日まで）の母親と乳児で、母子ともに医療行為が不要な方を対象に、心身のケア・授乳指導・育児相談等を提供します。サービスは、施設に宿泊する「宿泊型」（最大7日間、原則9時入所〜16時退所）、日中に施設へ通う「通所型」（最大7日間、9時〜16時）があり、この2形態は同一ページ・同一申請の枠組みで案内されています。自宅で助産師の訪問を受ける「訪問型産後ケア事業」は、確認したところ別ページ・別事業として案内されており、宿泊・通所型を利用している場合でも訪問型は改めて申請が必要とされています（訪問型は1回1,000円、5回まで利用可）。感染症にかかっている方や疑いのある方は利用できないとされています。申請は妊娠8か月以降からオンラインシステム（e-KOBE等）で行い、申請から利用承認まで約5営業日かかるとされています。神戸市には別に「産前産後ホームヘルプサービス」という家事支援の制度もありますが、これは産後ケア事業とは別の制度です。', '出産のあと、神戸市に住む生後1年未満の赤ちゃんとお母さんが、助産師さんなどから体と心のケアや育児の相談を受けられる制度です。施設に泊まる「宿泊型」、日帰りで通う「通所型」があり、自宅に来てもらう「訪問型」は別の申し込みが必要な制度として用意されています。妊娠8か月ごろからオンラインで申し込めるとされています。料金は所得により軽減される場合があります。', 'service', '神戸市に住所があり、産後1年以内（子どもの1歳の誕生日の前日まで）の母親と乳児で、母子ともに医療行為が不要な方が対象となる可能性があります。感染症にかかっている方や疑いのある方は利用できないとされています。', '宿泊型・通所型の1回あたり料金は、課税世帯が宿泊3,000円・通所2,000円、市民税非課税世帯が宿泊1,500円・通所1,000円、生活保護世帯が宿泊1,000円・通所800円とされ、多胎児の場合は追加料金（宿泊500円・通所300円）があるとされています。訪問型は別制度で1回1,000円（5回まで）、非課税世帯・生活保護世帯は無料となる可能性があります。正確な料金は公式ページで確認してください。', '妊娠8か月以降から申請でき、申請から利用承認まで約5営業日かかるとされています。具体的な期限は公式ページで確認してください。', 'オンラインシステムでアカウント作成後、「神戸市に申請」ボタンから申請するとされています（訪問型はe-KOBEから申請）。', '登録用メールアドレスが必要とされ、母子健康手帳は利用時に持参するとされています。そのほかの必要書類は公式ページで確認してください。', TRUE, 'お住まいの区役所・支所保健福祉課（神戸市こども家庭局家庭支援課）', '', NULL, 'https://www.city.kobe.lg.jp/a86732/kosodate/maternity/consult/sangokea.html', '神戸市：産後ケア事業（宿泊・通所）', '2026-07-01', 'medium', ARRAY['contactPhone', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本内容は確認日時点の神戸市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。特に、宿泊・通所型と訪問型は別事業・別申請となっているため、利用したいサービスに応じて公式ページで申請方法を個別に確認してください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
