insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'kawasaki'), 'kanagawa-kawasaki-postpartum-care', '産後ケア事業', '川崎市が母子保健法に基づき実施する産後ケア事業。出産後は心身ともに不安定になりやすい時期に、初めての育児への不安、授乳がうまくいかない、赤ちゃんのお世話や生活リズムがつかめない、お産や育児の疲れから体調がすぐれないといった場合に、川崎市助産師会・医療機関・訪問看護事業所等で心身のケアや育児支援を受けられる事業です。施設に宿泊する「宿泊型」（1泊2日〜最大6泊7日）、日中に施設で過ごす「日帰りロング型」（1回6時間）・「日帰りショート型」（1回90分）、自宅で受ける「訪問型」（1回90分）、医療的支援が必要な場合の「医療型」があります。川崎市に住所のある乳児とその母親が対象となる可能性があり、宿泊型・医療型は生後4か月未満、日帰り型・訪問型は1歳未満の子どもが目安とされていますが、詳細な対象要件・利用回数の上限・利用料金の減免条件などは公式ページで確認してください。', '出産のあと、お母さんと赤ちゃんが助産師さんなどから体と心のケアや育児の相談を受けられる川崎市の制度です。施設に泊まる「宿泊型」、日帰りで通う「日帰り型」、自宅に来てもらう「訪問型」などから選べます。川崎市に住んでいる方が対象になる可能性があり、料金や申し込み方法は市の公式ページで確認してください。', 'service', '川崎市に住所のある乳児とその母親が対象となる可能性があります。宿泊型・医療型は子どもが生後4か月未満、日帰り型・訪問型は1歳未満であることが目安とされています（在胎36週6日までに出産した場合は修正月齢での取り扱いとなる可能性があります）。詳細な要件は公式ページまたは窓口で確認してください。', '公式ページ本文の記載によれば、基本料金は宿泊型・医療型が1泊2日15,000円（延泊ごとに7,500円追加）、日帰りロング型が1回7,500円、日帰りショート型が1回4,000円、訪問型が1回5,000円とされています。市民税非課税世帯・生活保護世帯には減免制度があり、生活保護世帯は無料、市民税非課税世帯は宿泊型・日帰りロング型が2,500円・その他は無料などの記載がありますが、減免の適用条件（利用回数上限との関係等）は複雑なため、正確な自己負担額は必ず公式ページまたは窓口で確認してください。', '妊娠32週から申請可能とされており、妊娠中の申請が推奨されています。具体的な期限の定めがあるかは公式ページで確認してください。', 'オンライン申請システム「e-KAWASAKI」から利用申請を行います。申請後おおよそ10日程度でe-KAWASAKI内のマイページに「利用承認通知書」が届き、その後、利用を希望する実施施設（川崎市助産師会、医療機関、訪問看護事業所等）へ利用者本人が直接電話して予約する流れとされています。', 'e-KAWASAKIでの申請後に発行される利用承認通知書が必要です。市民税非課税世帯は非課税証明書、生活保護世帯は被保護証明書等、減免を受ける場合は追加書類が必要となる可能性があります。詳細は公式ページまたは窓口で確認してください。', TRUE, '川崎市 こども未来局 児童家庭支援・虐待対策室 母子保健担当', '044-200-2450', NULL, 'https://www.city.kawasaki.jp/450/page/0000061707.html', '川崎市 : 産後ケアのご案内', '2026-07-01', 'medium', ARRAY['benefitAmountText（減免の適用条件・利用回数上限との関係、非課税世帯減免と一般減免の併用可否が公式ページ本文の要約だけでは判然としないため）', 'applicationDeadlineText（明確な申請締切の有無）', 'requiredDocumentsText（減免申請時の追加書類の詳細）', 'targetPeople（在胎週数36週6日以降・以前での月齢の扱いの詳細）']::text[], '本内容は確認日時点の川崎市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
