insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'sagamihara'), 'kanagawa-sagamihara-postpartum-care', '産後ケア事業', '相模原市が実施する産後ケア事業。「育児を手伝ってもらえる人がいない」「赤ちゃんのお世話の仕方がわからず不安」といった産後の育児・体調への不安を抱えるお母さんを対象に、医療機関や助産院への宿泊(宿泊型)、日中の通所(通所型)、助産師等の自宅訪問(訪問型)のいずれかにより、心身のケア・授乳や沐浴のアドバイス・乳房ケア・育児相談などを受けられるサービスです。相模原市に住民登録のあるお母さんと赤ちゃん(1歳の誕生日の前日まで)で、産後ケアを必要とする方が対象となる可能性があります。利用料金は宿泊型・通所型・訪問型それぞれ回数に応じて設定されており、市県民税非課税世帯は半額、生活保護受給世帯は全額免除となる可能性があります。3種類のサービスを通算して7日(回)以内(多胎児は14日(回)以内)が利用の目安とされています。詳細な対象要件・料金・実施施設は公式ページおよび市の窓口で必ず確認してください。', '出産のあと、育児や体調に不安があるお母さんと赤ちゃんが、助産師さんなどから心と体のケアや授乳・育児の相談を受けられる相模原市の制度です。助産院などに泊まる「宿泊型」、日中に通う「通所型」、自宅に来てもらう「訪問型」があります。相模原市に住民登録がある方が対象になる可能性があり、料金や利用回数などは市のページで確認してください。', 'service', '相模原市に住民登録のある、産後のお母さんと赤ちゃん(1歳の誕生日の前日まで)で、育児や体調に不安があるなど産後ケアを必要とする方が対象となる可能性があります。詳細な要件は公式ページでご確認ください。', '宿泊型: 初日〜5日目は1日2,500円、6日目以降は1日5,000円。通所型: 初回〜5回目は1回1,000円、6回目以降は1回2,000円。訪問型: 初回〜5回目は1回1,500円、6回目以降は1回3,000円。市県民税非課税世帯は半額、生活保護受給世帯は全額免除となる可能性があります(いずれも公式ページ・チラシで要確認)。', NULL, '妊娠8か月(28週)以降を目安に、利用を希望する実施施設(協力医療機関・協力助産院)へ直接予約・調整します。サービス利用日に「産後ケア事業利用申請書」を施設へ提出する方式で、インターネット経由のオンライン申請システムは公式ページ上には見当たりませんでした。', '産後ケア事業利用証(母子健康手帳別冊に同封)、母子健康手帳、利用料。減免を希望する場合は課税証明書(写)など。', FALSE, '相模原市 こども家庭課(保健事業班)', '042-769-8345', NULL, 'https://www.city.sagamihara.kanagawa.jp/kosodate/1026602/kosodate/1026604/1021109.html', '産後ケア事業｜相模原市', '2026-07-01', 'high', ARRAY['applicationDeadlineText', '実施施設の最新の受入状況・空き状況']::text[], '本内容は確認日時点の相模原市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
