insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'yokohama'), 'kanagawa-yokohama-postpartum-care', '横浜市産後母子ケア事業（訪問型・デイケア・ショートステイ）', '横浜市が実施する産後母子ケア事業。出産後のお母さんと赤ちゃんを対象に、助産師等のアドバイスを受けながら育児方法を学べる場として、助産師が自宅を訪問する「訪問型」、日帰りで施設を利用する「母子デイケア」、宿泊する「母子ショートステイ」の3つの形で提供します。対象者の詳細な条件は公式ページ本文には明記が薄く、子育て応援アプリ「パマトコ」の事業概要ページでの確認が案内されています。令和8年4月から、デイケアはこれまでの「産後に心身の不調や育児不安がある方」等の利用要件が撤廃され、対象期間も生後4か月未満から6か月未満に延長されたとされています。訪問型・デイケア・ショートステイのいずれも妊娠28週以降からの申請が可能とされています。正確な対象条件・料金は公式ページで確認してください。', '出産のあと、お母さんと赤ちゃんが助産師さんのアドバイスを受けながら育児を学べる横浜市の制度です。自宅に来てもらう「訪問型」、日帰りで通う「デイケア」、施設に泊まる「ショートステイ」から選べます。子育て応援アプリ「パマトコ」から申し込みます。対象条件や料金は公式ページで確認するとよいでしょう。', 'service', '対象者の詳細な条件は公式ページ本文に明記が薄く、「パマトコ」の事業概要ページでの確認が案内されています。令和8年4月からデイケアについては「産後に心身の不調や育児不安がある方」等の利用要件が撤廃されたとされ、対象期間も生後6か月未満に延長されたとされています。訪問型・ショートステイを含め、正確な対象条件は公式ページまたはパマトコで確認してください。', '訪問型は1回（90分程度）1,500円、母子デイケアは1日2,400円、母子ショートステイは1泊2日で6,000円（以後1日追加ごとに3,000円）とされています。減免制度の有無については公式ページ本文で確認できませんでした。正確な金額は公式ページで確認してください。', '妊娠28週以降から申請可能とされ、審査完了までに10営業日程度かかるとされています。具体的な締切等は公式ページで確認してください。', '横浜市子育て応援アプリ「パマトコ」からのオンライン申請とされています。ショートステイについては事前に区役所での面談が必要とされています。', '公式ページ本文には必要書類の一覧が明記されていませんでした。パマトコでの申請時に案内される情報の入力が必要とみられます。詳細は公式ページまたはパマトコで確認してください。', TRUE, '横浜市こども青少年局こども福祉保健部地域子育て支援課（訪問型の利用調整は横浜市助産師会事務局）', '045-671-2455', 'https://pamatoco.city.yokohama.lg.jp/ctz/contents/a04J4000000vGv9IAE/%E6%A8%AA%E6%B5%9C%E5%B8%82%E7%94%A3%E5%BE%8C%E6%AF%8D%E5%AD%90%E3%82%B1%E3%82%A2%E4%BA%8B%E6%A5%AD%E8%A8%AA%E5%95%8F%E5%9E%8B%E6%AF%8D%E5%AD%90%E3%82%B1%E3%82%A2%E5%88%A9%E7%94%A8%E7%94%B3%E8%AB%8B', 'https://www.city.yokohama.lg.jp/kosodate-kyoiku/oyakokenko/ninshin/sangoboshikea.html', '横浜市産後母子ケア事業 横浜市', '2026-07-01', 'medium', ARRAY['targetPeople', 'requiredDocumentsText', 'benefitAmountText']::text[], '本内容は確認日時点の横浜市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよびパマトコ、市の窓口で最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
