insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kumamoto' and m.slug = 'kumamoto'), 'kumamoto-kumamoto-postpartum-care', '熊本市産後ケア事業', '熊本市が実施する産後ケア事業。出産後のお母さんと赤ちゃんを対象に、助産師等の看護職が中心となり、心身のケア・授乳相談・育児相談などを、施設に宿泊する「宿泊型」、施設に日帰りで通う「日帰り型」、自宅で受ける「訪問型」の3つの形で提供します。産後1年未満で、身体的な不調や回復の遅れ、授乳の困難、精神的な不調など支援を必要とする熊本市内在住の母子が対象となる可能性があります。令和6年4月1日から事前申請が不要となり、利用希望者が実施施設に直接電話予約する方式に変わったとされています。利用料金は世帯の課税状況等により異なり、非課税世帯・生活保護世帯には減免がある可能性があります。利用回数の上限や対象となる具体的な状況などの詳細は、必ず公式ページで確認してください。', '出産のあと、お母さんと赤ちゃんが助産師さんなどから体と心のケアや授乳・育児の相談を受けられる熊本市の制度です。施設に泊まる「宿泊型」、日帰りで通う「日帰り型」、自宅に来てもらう「訪問型」があります。熊本市に住む産後1年未満の方が対象になる可能性があり、料金や回数などは市の公式ページで確認してください。', 'service', '熊本市内に住民票があり、産後1年未満の母子で、身体的な不調・回復の遅れ、授乳の困難（乳房トラブルを含む）、産後の精神的な不調、継続的な保健指導や身体的ケアが必要な状態、または家族から家事・育児の支援を受けられない状況など、支援を必要とする方が対象となる可能性があります。感染性疾患に罹患している場合や医療的介入が必要な産婦は対象外とされています。詳細な該当要件は公式ページまたは窓口で確認してください。', '自己負担額の目安（一般世帯／非課税世帯／生活保護世帯の順、多胎児は1子あたり500円加算）。宿泊型：8,000円／3,500円／1,750円。日帰り1日型：3,000円／1,500円／750円。日帰り3時間型：1,800円／750円／300円。日帰り2時間型：1,200円／500円／200円。訪問型：1,200円／500円／200円。このほか食事代や交通費等の実費が別途かかる場合があります。金額や区分は変更される可能性があるため公式ページで確認してください。', '常時利用可能な事業とみられ、明確な申請期限の記載は公式ページ上に見当たりませんでした。利用回数の上限（宿泊型・日帰り型・訪問型あわせて10回）に達するまでの利用が想定されます。', '令和6年4月1日から事前申請が不要となり、利用を希望する方が直接、実施施設（委託を受けた病院・診療所・助産所等）に電話で予約する方式に変わったとされています。', '利用時には親子（母子）健康手帳と、母子健康手帳受け取り時に配布される利用カードの持参が必要とされています。非課税世帯の減免を受ける場合は所得証明書、生活保護世帯の場合は証明書類の提示が利用の都度必要とされています。', FALSE, '熊本市こども局こども育成部こども支援課', '096-328-2158', NULL, 'https://www.city.kumamoto.jp/kiji00333589/index.html', '熊本市産後ケア事業について / 熊本市公式サイト', '2026-07-01', 'high', ARRAY['applicationDeadlineText', '利用回数上限の運用細則', '宿泊型・日帰り型・訪問型それぞれの実施施設一覧']::text[], '本内容は確認日時点の熊本市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
