insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei postpartum-care import', '{"slug":"kumamoto-kumamoto-postpartum-care","status":"published","title":"熊本市産後ケア事業","officialUrl":"https://www.city.kumamoto.jp/kiji00333589/index.html","topic":"postpartum-care"}'::jsonb, 'seirei:kumamoto-kumamoto-postpartum-care:a3VtYW1vdG8ta3VtYW1vdG8tcG9zdHBhcnR1bS1jYXJlfGRzaFJXRGVGaTRHcVRKQXBIYnlqZ0Y3Yw==' from public.support_programs sp where sp.slug='kumamoto-kumamoto-postpartum-care' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kyoto' and m.slug = 'kyoto'), 'kyoto-kyoto-postpartum-care', '京都市スマイルママ・ホッと事業（産後ケア事業）', '京都市が実施する産後ケア事業「スマイルママ・ホッと事業」。京都市に住民票があり市内に居住する、生後1年未満の赤ちゃんとその母親を対象に、産科医療機関や助産所等で助産師等の専門職による心身のケア・育児サポートを提供します。サービス形態は施設に宿泊する「産後ショートステイ」（24時間以内、最大7回）と、日中に施設へ通う「産後デイケア」（午前10時〜午後6時、最大7回）があります。自宅で受ける「アウトリーチ（訪問型）」も案内されていますが、確認日時点では2026年8月1日からの開始予定とされており、現時点ではまだ開始されていない可能性があります。妊娠中の申請はできないとされ、出産後に申請する必要があります。市民税課税世帯は最大5回まで1回あたり2,500円の減免があり、非課税世帯・生活保護世帯は無料となる可能性があります。発熱や入院治療が必要な感染症がある場合は利用できないとされています。', '出産のあと、生後1年未満の赤ちゃんとお母さんが、助産師さんなどから体と心のケアや育児の相談を受けられる京都市の制度です。施設に泊まる「ショートステイ」、日帰りで通う「デイケア」があり、自宅で受ける「訪問型」も2026年8月から始まる予定とされています。申請は出産後にできます。料金は所得に応じて軽減される場合があり、京都市の窓口で確認してください。', 'service', '京都市に住民票があり市内に居住する、生後1年未満の赤ちゃんとその母親が対象となる可能性があります。発熱や入院治療が必要な感染症がある場合は利用できないとされています。妊娠中の申請はできず、出産後の申請が必要とされています。', '市民税課税世帯は最大5回まで1回2,500円の減免があるとされ、減免後の自己負担はショートステイが1,200〜3,600円程度、デイケアが0〜1,200円程度とされています。非課税世帯・生活保護世帯は無料となる可能性があります。正確な料金体系は公式ページで確認してください。', '妊娠中の申請はできないとされ、出産後の申請となります。具体的な申請期限（利用希望日の何日前までかなど）は公式ページに明記が確認できなかったため、京都市子ども家庭支援課で確認してください。', '電子申請フォームでの申請ができるとされています（入力時間目安は約5〜10分）。電子申請が難しい場合は子どもはぐくみ室等の窓口へ問い合わせる案内があります。', '必要書類の詳細は公式ページ本文に明記が確認できませんでした。母子健康手帳等が必要になる可能性が高いですが、正確には京都市子ども家庭支援課で確認してください。', TRUE, '京都市子ども若者はぐくみ局子ども若者未来部子ども家庭支援課', '075-222-3939', NULL, 'https://www.city.kyoto.lg.jp/hagukumi/page/0000168986.html', '京都市：産後のお母さんをしっかりサポート！京都市スマイルママ・ホッと事業（産後ケア事業）について', '2026-07-01', 'medium', ARRAY['requiredDocumentsText', 'applicationDeadlineText', 'benefitAmountText']::text[], '本内容は確認日時点の京都市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。訪問型（アウトリーチ）は確認日時点で開始前の予定情報である可能性があるため、特に公式ページでの確認をおすすめします。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
