insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'miyagi' and m.slug = 'sendai'), 'miyagi-sendai-postpartum-care', '産後ケア事業（宿泊・デイサービス・訪問）', '仙台市が実施する産後ケア事業。病院・診療所・助産所において、宿泊、デイサービス（日帰り）、訪問のいずれかの形で、母体の回復のための支援、育児指導、生活相談等のサービスを提供するとされています。仙台市内に住所があり、出産後で家族等から十分な家事・育児の援助が受けられない、産後に心身の不調や育児不安があるなどの状況にある方が対象となる可能性がありますが、公式ページ本文には対象者要件の詳細な記載が確認できず、案内チラシでの確認が必要とみられます。利用料は課税世帯・非課税世帯・生活保護世帯で異なり、宿泊型は1日5,500円、デイサービス型は2時間1,000円・6時間3,200円、訪問型は2時間2,000円・4時間3,800円（非課税・生活保護世帯は無料）とされています。妊娠32週から申請できるとされていますが、対象者の詳細条件・必要書類などは公式ページおよびチラシで必ず確認してください。', '出産のあと、お母さんと赤ちゃんが宿泊・日帰り・訪問のいずれかの形で体や育児のサポートを受けられる仙台市の制度です。仙台市に住んでいる方が対象になる可能性があります。料金は世帯の状況によって変わります。詳しい対象条件は市のチラシや窓口で確認するとよいでしょう。', 'service', '仙台市内に住所がある方が対象となる可能性があります。検索結果の一部には「仙台市内に住所を有する生後12か月未満の乳児とその母親で、家族等から十分な家事及び育児等の援助が受けられず、産後に心身の不調又は育児不安等がある方」という条件が示唆されていましたが、公式ページ本文で明示的に確認することはできませんでした。正確な対象条件は公式ページのチラシ、または区役所家庭健康課で確認してください。', '課税世帯：宿泊型5,500円/日、デイサービス型2時間1,000円・6時間3,200円、訪問型2時間2,000円・4時間3,800円。非課税世帯・生活保護世帯：いずれも0円とされています。正確な金額は公式ページで確認してください。', '妊娠32週から申請できるとされています。申請後1週間程度で利用決定の通知があるとされていますが、具体的な締切等は公式ページで確認してください。', '電子申請（せんだいオンライン申請サービス）、窓口申請、郵送申請のいずれかが可能とされています。', '申請書（様式第1号）、母子健康手帳が必要とされ、該当者は生活保護受給証明書や市民税非課税状況がわかる書類が必要とされています。詳細は公式ページで確認してください。', TRUE, '仙台市こども若年局こども家庭保健課（各区役所家庭健康課でも相談可）', '022-214-8189', NULL, 'https://www.city.sendai.jp/kodomo-hoken/kurashi/kenkotofukushi/kosodate/joho/joho/sangokea.html', '産後ケア事業｜仙台市', '2026-07-01', 'medium', ARRAY['targetPeople', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本内容は確認日時点の仙台市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。特に対象者の詳細条件は本文で確認しきれていないため、必ず公式チラシまたは窓口でご確認ください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
