insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei postpartum-care import', '{"slug":"miyagi-sendai-postpartum-care","status":"review","title":"産後ケア事業（宿泊・デイサービス・訪問）","officialUrl":"https://www.city.sendai.jp/kodomo-hoken/kurashi/kenkotofukushi/kosodate/joho/joho/sangokea.html","topic":"postpartum-care"}'::jsonb, 'seirei:miyagi-sendai-postpartum-care:bWl5YWdpLXNlbmRhaS1wb3N0cGFydHVtLWNhcmV8ZTJMbld1MXZCcW5TanRDRWZReFlRbW1R' from public.support_programs sp where sp.slug='miyagi-sendai-postpartum-care' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'niigata' and m.slug = 'niigata'), 'niigata-niigata-postpartum-care', '新潟市産後ケア事業', '新潟市が実施する産後ケア事業。委託医療機関等での産後ケアを通じて、親子の愛着形成を促し、家庭での育児がスムーズに行えるよう、出産後のお母さんの心身のケアや育児サポートなどを行います。サービスは施設に宿泊する「宿泊ケア」、施設に通う「デイケア」、自宅で受ける「訪問ケア」の3種類があり、産後の身体・乳房管理や生活面の指導、沐浴・授乳等の育児指導、その他必要な保健指導が行われます。新潟市に住所があり、家族などから十分な家事・育児の援助を受けられない産婦および生後6か月未満の児（訪問ケアは1歳未満の児）で、産後の心身の不調や育児不安がある方、その他特に支援が必要と認められる方（流産・死産等を経験された方を含む）が対象となる可能性があります。利用料は自己負担額として設定されていますが、市民税非課税世帯・生活保護世帯は半額になるとされ、各サービスの初回利用は無料とされています。詳しい対象条件・料金・利用可能施設・回数の上限などは、必ず新潟市の公式ページで確認してください。', '出産のあと、お母さんと赤ちゃんが心と体のケアや育児の相談を受けられる新潟市の制度です。施設に泊まる「宿泊ケア」、日帰りで通う「デイケア」、自宅に来てもらう「訪問ケア」から選べます。新潟市に住んでいて、家族などから十分な手助けを受けられない方などが対象になる可能性があり、料金や回数などは市の公式ページで確認してください。', 'service', '新潟市に住所を有し、家族などから十分な家事・育児の援助が受けられない産婦および生後6か月未満の児（訪問ケアは1歳未満の児、低出生体重児は修正月齢で判定）で、次のいずれかに該当する方が対象となる可能性があります。(1)産後に心身の不調または育児不安などがある方、(2)その他、特に支援が必要と認められる方（流産・死産等を経験された方も利用できるとされています）。詳しい該当条件は公式ページまたは区役所健康福祉課で確認してください。', '自己負担額（公式ページ記載）: 宿泊ケア 2,500円/日（1泊2日の場合5,000円、食事3回提供あり）、デイケア 2,000円/日（食事1回提供あり）、訪問ケア 1,000円/回（90分/回）。市民税非課税世帯および生活保護世帯は自己負担額が半額になるとされています。各サービスとも1日（回）目は無料とされています。多胎児加算料が別途生じる場合がありますが、宿泊ケア5,000円・デイケア3,000円・訪問ケア2,000円を上限に市が助成するとされています。利用可能回数は宿泊ケア最大7日、デイケアと訪問ケアは合算して7日（回）、審査により通算7日（回）を限度に延長できる場合があるとされています。市の産後ケア事業の内容以外のサービス（利用時間の延長、特別室利用、リフレッシュマッサージ等）は全額自己負担とされています。正確な金額・条件は必ず公式ページで確認してください。', '妊娠8か月以降から利用希望日の10日前までに申請が必要とされています。', '電子申請システム（新潟市の電子申請フォーム、外部サイト）で申請するか、「新潟市産後ケア事業利用申請書」に記入のうえ、お住まいの区の区役所健康福祉課（妊娠・子育てほっとステーション）へ提出するとされています。申請後、区役所の助産師や保健師から体調や育児不安の状況等について連絡があり、利用者として認定された場合に「決定通知書」「利用管理票」「無料チケット」等が送付されるとされています。利用施設は自分で選び、利用日や内容を施設と相談する流れとされています。', '「新潟市産後ケア事業利用申請書」（公式ページよりPDF様式を入手可能、または電子申請フォームで入力）。詳しい添付書類の要否は公式ページまたは窓口で確認してください。', TRUE, '各区役所健康福祉課健康増進係（妊娠・子育てほっとステーション）／新潟市役所こども家庭課母子保健グループ', '025-226-1205', 'https://lgpos.task-asp.net/cu/151009/ea/residents/procedures/apply/3e0b0d5f-f296-4d6f-9106-edbb4a476541/start', 'https://www.city.niigata.lg.jp/kosodate/ninshin/nenrei/ninshinsyusan/sangokea.html', '新潟市産後ケア事業　新潟市', '2026-07-01', 'high', ARRAY['requiredDocumentsText（申請書以外の添付書類の要否は明記が薄いため要確認）', '実施施設ごとの多胎児加算料の具体額（施設ごとに異なるとされ、上限額のみ確認）']::text[], '本内容は確認日時点の新潟市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
