insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'okayama' and m.slug = 'okayama'), 'okayama-okayama-postpartum-care', '産後ケア事業', '岡山市が母子保健法に基づき実施する産後ケア事業。出産後1年未満のお母さんと赤ちゃんを対象に、産科医療機関・助産所や自宅で、心身のケアや育児サポートなどの支援を、施設に宿泊する「宿泊型」、施設に日帰りで通う「日帰り型」、助産師等が自宅を訪問する「訪問型」の3つの形で提供します。出産予定日の2か月前から電子申請でき、市の審査を経て利用決定通知（電子クーポン）が発行された後、施設に予約する流れとなる可能性があります。利用日時点で岡山市に住民票がある方が対象となる可能性があり（流産・死産を経験された方を含む）、入院治療が必要な場合は対象外とされています。利用料金・利用可能日数・自己負担額の減免などの詳細は、必ず公式ページおよび市の窓口で確認してください。', '出産後1年未満のお母さんと赤ちゃんが、助産師さんなどから体と心のケアや育児の相談を受けられる岡山市の制度です。施設に泊まる「宿泊型」、日帰りで通う「日帰り型」、自宅に来てもらう「訪問型」から選べる可能性があります。岡山市に住んでいる方が対象になる可能性があり、料金や回数などは市のページで確認してください。', 'service', '産後1年未満の母親とその赤ちゃんで、利用日時点で岡山市に住民票がある方が対象となる可能性があります（流産・死産を経験された方を含む場合があるとされています）。ただし、入院治療が必要な場合は対象外とされています。詳細な要件は公式ページで確認してください。', '施設利用にかかる費用のうち、市が定める額を除いた自己負担分を利用者が支払う仕組みとされています。生活保護世帯・市民税非課税世帯は宿泊1泊29,000円・日帰り1日13,000円・訪問1回7,000円、それ以外の世帯は宿泊1泊25,000円・日帰り1日12,000円・訪問1回6,000円までが公費負担の目安とされ、多胎児の場合は加算があるとされています。利用回数は単胎児で宿泊・日帰り合計7日以内かつ訪問3回以内、多胎児で宿泊・日帰り合計10日以内かつ訪問5回以内とされています。実際の自己負担額は施設ごとに異なる可能性があるため、必ず公式ページおよび施設・窓口で確認してください。', '明確な申請期限の記載は確認できませんでした。出産予定日の2か月前から電子申請が可能とされていますが、詳細は公式ページまたは窓口で確認してください。', '公式ページで案内されている電子申請システム（e-tumo、岡山市産後ケア事業利用申請書）から申請する方法が案内されています。妊娠中の方向け・産後の方向けでそれぞれ別の申請フォームがあるとされています。申請後、市の審査を経て利用決定通知メール（電子クーポン発行）が届き、その後に対象施設へ予約する流れとされています。詳細は公式ページで確認してください。', '公式ページ本文には必要書類の一覧が明記されていませんでした。生活保護世帯・市民税非課税世帯など申請内容によっては添付書類が必要になる場合があるとされていますが、具体的な書類名は確認できていません。必要書類については公式ページまたは市の窓口で確認してください。', TRUE, '岡山市保健福祉局保健所健康づくり課 母子歯科保健係', '086-803-1264', 'https://www.city.okayama.jp/kurashi/0000020851.html', 'https://www.city.okayama.jp/kurashi/0000020851.html', '産後ケア事業 | 岡山市', '2026-07-01', 'medium', ARRAY['applicationDeadlineText', 'requiredDocumentsText', 'benefitAmountText（施設ごとの実費・自己負担額の詳細、減免の具体的条件）', 'ページの最終更新日（本文中に2019年9月30日の記載と令和8年7月1日現在の施設情報の記載が混在しており、内容全体がどの時点のものか特定できない）']::text[], '本内容は確認日時点の岡山市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
