insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'osaka' and m.slug = 'osaka'), 'osaka-osaka-postpartum-care', '大阪市産後ケア事業', '大阪市が実施する産後ケア事業。大阪市に住所があり、出産後1年未満の母親と乳児で、産後ケアを必要とし、各区保健福祉センター所長が利用を適当と判断した方が対象となる可能性があります。サービスは、施設に宿泊する「ショートステイ」（1泊2日〜6泊7日）、日中に施設へ通う「デイケア」（最大7日間）、自宅で助産師等の訪問を受ける「アウトリーチ」（1回2時間程度、最大5回）の3形態があります。アウトリーチについては流産・死産でお子さまを亡くされた方も対象となる可能性があるとされています。申請は妊娠8か月以降からサービス利用希望日の2週間前までに、大阪市行政オンラインシステムまたは各区保健福祉センター窓口で行うとされています。非課税世帯・生活保護世帯には利用料の減免があります。', '出産のあと、大阪市に住む生後1年未満の赤ちゃんとお母さんが、助産師さんなどから体と心のケアや育児の相談を受けられる制度です。泊まる「ショートステイ」、日帰りで通う「デイケア」、自宅に来てもらう「アウトリーチ」から選べます。妊娠8か月ごろから、利用したい日の2週間前までにオンラインまたは窓口で申し込めるとされています。料金は所得により軽減される場合があります。', 'service', '大阪市に住所があり、出産後1年未満の母親と乳児で、産後ケアを必要とし、各区保健福祉センター所長が利用を適当と判断した方が対象となる可能性があります。アウトリーチについては、流産・死産でお子さまを亡くされた方も対象となる可能性があるとされています。', '通常料金はショートステイが1泊2日4,250円（以降1日2,125円加算）、デイケアが1日1,500円、アウトリーチが1回500円とされています。非課税世帯・生活保護世帯は減免され、ショートステイ2,500円、デイケア1,000円、アウトリーチ無料となる可能性があります。正確な料金は公式ページで確認してください。', '妊娠8か月以降から、サービス利用希望日の2週間前までに申請するとされています。', '大阪市行政オンラインシステムでのオンライン申請、または各区保健福祉センター窓口での申請ができるとされています。', '母子健康手帳、大阪市産後ケア事業利用登録申請書が必要とされています。減免を希望する場合は、生活保護受給証明書または市府民税非課税証明書が必要となる可能性があります。', TRUE, '大阪市こども青少年局子育て支援部管理課母子保健グループ', '06-6208-9966', NULL, 'https://www.city.osaka.lg.jp/kodomo/page/0000370578.html', '産後ケア事業について - 大阪市', '2026-07-01', 'high', ARRAY['benefitAmountText']::text[], '本内容は確認日時点の大阪市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
