insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'osaka' and m.slug = 'sakai'), 'osaka-sakai-postpartum-care', '堺市産後ケア事業', '堺市が実施する産後ケア事業。堺市民で生後1歳未満の赤ちゃんとその母親を対象に、助産師等の専門スタッフから心身のケアや育児のアドバイスを受けられる制度です。サービスは、施設に宿泊し母子同室でサポートを受ける「宿泊型」（1泊2日、3食付）、日中に施設を利用する「デイサービス型」（1日、2食付）、助産師が自宅を訪問する「訪問型」（2時間または3時間）の3形態があります。宿泊型・デイサービス型は、周りに支援してくれる人がなく育児の不安や疲れなどで自宅での子育てに困難を感じている方が対象とされ、赤ちゃんと母親に感染症の疑いや入院治療の必要がないことが条件とされています。妊娠28週以降から、利用開始日の10日前までに、各区子育て支援課窓口または電子申請システムで申請するとされています。非課税世帯・生活保護世帯には大幅な減額があります。', '出産のあと、堺市に住む生後1歳未満の赤ちゃんとお母さんが、助産師さんなどから体と心のケアや育児の相談を受けられる制度です。泊まる「宿泊型」、日帰りで通う「デイサービス型」、自宅に来てもらう「訪問型」があります。妊娠28週ごろから、利用したい日の10日前までに区の窓口かオンラインで申し込めるとされています。料金は所得により軽減される場合があります。', 'service', '堺市民で生後1歳未満の赤ちゃんとその母親が対象となる可能性があります。宿泊型・デイサービス型は、周りに支援してくれる人がなく育児の不安や疲れなどで自宅での子育てに困難を感じている方が対象とされ、赤ちゃんと母親に感染症の疑いや入院治療の必要がないことが条件とされています。', '通常料金は宿泊型5,200円/泊、デイサービス型2,600円/日、訪問型3,500円/回とされています。減額後は宿泊型3,500円、デイサービス型2,300円、訪問型1,000円（各1回につき5回まで）となる可能性があり、市民税非課税世帯・生活保護世帯はさらに大幅な減額があるとされています。正確な料金は公式ページで確認してください。', '妊娠28週以降から申請可能で、利用開始日の10日前までに申請するとされています。', '各区子育て支援課窓口での申請、または電子申請システムでのオンライン申請ができるとされています。', '利用申請書、母子健康手帳が必要とされています。減額を希望する場合は、市府民税非課税証明書または被保護証明書が必要となる可能性があります。', TRUE, '堺市こども青少年局こども青少年育成部こども育成課', '072-228-7612', NULL, 'https://www.city.sakai.lg.jp/kosodate/hughug/ninshin_shusan/ninshin/sangokea-syukuhaku.html', '堺市 産後ケア事業のご案内　堺市', '2026-07-01', 'high', ARRAY['benefitAmountText']::text[], '本内容は確認日時点の堺市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
