insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'saitama' and m.slug = 'saitama'), 'saitama-saitama-postpartum-care', '産後ケア事業（訪問型・デイサービス型・宿泊型）', 'さいたま市が実施する産後ケア事業。出産後のお母さんと赤ちゃんの新生活を応援するため、助産師等による心身のケアや育児指導等を、訪問型（早期・あんしんの2種）、デイサービス型、宿泊型の形で提供します。さいたま市内に住民票があり、生後1年未満の赤ちゃんとそのお母さんで、赤ちゃん・お母さんともに医療行為が不要な方が対象となる可能性があります。公式ページでは「家族等から育児の支援を十分に受けられない方」「産後に心身の不調や育児不安がある方」といった状況が例として挙げられていますが、これらは典型例としての記載とみられます。利用料は課税世帯・非課税世帯等で異なり、クーポン券を利用する仕組みがあるとされています。妊娠8か月（28週）以降から申請可能で、1回の出産につき7回まで利用できるとされています。正確な条件・料金は公式ページで確認してください。', '出産のあと、お母さんと赤ちゃんが助産師さんなどから体と心のケアや育児の相談を受けられるさいたま市の制度です。自宅に来てもらう「訪問型」、日帰りで通う「デイサービス型」、施設に泊まる「宿泊型」から選べます。さいたま市に住んでいる方が対象になる可能性があり、料金や回数などは公式ページで確認してください。', 'service', 'さいたま市内に住民票がある方で、生後1年未満の赤ちゃんとそのお母さん（施設により受入可能な月齢は異なるとされています）、赤ちゃん・お母さんともに医療行為が不要な方が対象となる可能性があります。「家族等から育児の支援を十分に受けられない」「産後に心身の不調や育児不安がある」といった状況が例として挙げられていますが、必須条件かどうかを含め詳細は公式ページで確認してください。', '課税世帯：訪問型（早期）2,700円（クーポン利用で1,350円）、訪問型（あんしん）450円（クーポン利用で220円）、デイサービス型5,000円（クーポン利用で2,500円）、宿泊型6,800円/泊（クーポン利用で4,300円/泊）。非課税・生活保護世帯：訪問型無料、デイサービス型450円、宿泊型900円/泊とされています。正確な金額は公式ページで確認してください。', '妊娠8か月（妊娠28週以降）から申請できるとされています。具体的な締切等は公式ページで確認してください。', 'さいたま市産後ケア事業の電子申請のほか、郵送・FAXでの申請も可能とされています。承認されると保健センターから利用承認通知書兼利用管理表とクーポン券が届くとされています。', '利用承認通知書兼利用管理表、クーポン券、母子健康手帳が必要とされ、非課税世帯等は別途証明書類の提出が必要とされています。詳細は公式ページで確認してください。', TRUE, 'さいたま市母子保健課すこやか支援係', '048-829-1588', NULL, 'https://www.city.saitama.lg.jp/003/001/011/sangocaregigyo.html', '産後ケア事業を利用してみませんか - さいたま市', '2026-07-01', 'high', ARRAY['targetPeople']::text[], '本内容は確認日時点のさいたま市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
