insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'shizuoka' and m.slug = 'hamamatsu'), 'shizuoka-hamamatsu-postpartum-care', '産後ケア事業', '浜松市が母子保健法に基づき実施する産後ケア事業。市内に居住する産後1年未満の母子を対象に、助産師等による母親の身体のケアや産後の生活指導、栄養指導、授乳ケア、沐浴や抱き方などの育児手技の指導・相談、生活相談などを、施設に宿泊する「宿泊型」、施設に日帰りで通う「デイサービス型（1日／1時間超／1時間以内など）」、自宅で受ける「訪問型」の形で提供します。利用にはあらかじめ申請が必要で、承認後に希望施設を予約して利用する流れとなる可能性があります。市民税課税状況等に応じた利用料の減免制度がある可能性があります。対象要件・利用料・利用回数・実施施設などの詳細は、公式ページおよび市の窓口で確認してください。', '出産後1年未満の赤ちゃんとお母さんが、助産師さんなどから体のケアや授乳・育児の相談を受けられる浜松市の制度です。施設に泊まる「宿泊型」、日帰りで通う「デイサービス型」、自宅に来てもらう「訪問型」から選べる可能性があります。事前の申請が必要で、料金や対象になるかどうかは市の窓口やホームページで確認してください。', 'service', '浜松市内に居住し、産後1年未満の母子が対象となる可能性があります。里帰り出産などで一時的に浜松市に滞在している場合も、条件によっては対象となる可能性がありますが、詳細は公式ページ・窓口で確認してください。医療行為が必要な場合は利用できない可能性があります。', '利用料は実施施設や利用形態（宿泊型・デイサービス型・訪問型、利用時間など）により異なります。市が公表している資料では、市民税課税世帯の基本自己負担額の目安として宿泊型20,000円、デイ1日型10,300円、デイ1時間型2,650円、デイ2時間型5,300円、訪問型6,000円程度、令和7年度からきょうだい児や生後4か月以降の児を同時に預ける場合の加算（宿泊型・デイ1日型で数千円程度）があるとされていますが、実際の窓口案内では「施設により異なる」ともされており、金額は変更される可能性があります。世帯の市民税非課税・生活保護受給などの場合は自己負担の減免制度がある可能性があります。正確な金額は必ず公式ページまたは窓口で確認してください。', '公式ページ上に明確な申請期限の記載は確認できませんでした。出産前後の一定期間内の申請が想定される可能性があるため、時期については窓口に確認してください。', 'オンライン申請（LINE公式アカウント「こども家庭センター」からの申請、または「浜松市産後ケア事業申請書兼同意書入力フォーム」による申請）、または申請書を印刷し各健康づくりセンターの窓口へ提出する方法があるとされています。1回の妊娠出産につき1回の申請で、宿泊型・デイサービス型・訪問型のすべてのサービス種別が利用可能になるとされています。申請後2〜3週間程度で健康増進課から「利用承認通知書」が郵送され、これを施設に持参・提示して予約・利用する流れとされています。', '窓口申請の場合、産後ケア事業利用申請書兼同意書、親子健康手帳（母子健康手帳）が必要とされています。転入者で市民税非課税等による減免を希望する場合は、市町村民税（非）課税証明書が必要になる可能性があります。', TRUE, '浜松市健康福祉部健康増進課 母子グループ', '053-453-6117', NULL, 'https://www.hamamatsu-pippi.net/contents/7915.html', '産後ケア事業 - 浜松市子育て情報サイト ぴっぴ', '2026-07-01', 'medium', ARRAY['benefitAmountText（施設ごとの実額・令和8年度時点の最新金額は資料により表現が異なるため要確認）', 'applicationDeadlineText（明確な期限記載が公式ページ上で見つからなかった）', 'targetPeople（里帰り出産等の例外要件の詳細）']::text[], '本内容は確認日時点の浜松市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
