insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'shizuoka' and m.slug = 'shizuoka'), 'shizuoka-shizuoka-postpartum-care', '静岡市産後ケア事業', '静岡市が母子保健法に基づき実施する産後ケア事業。出産後1年未満のお母さんと赤ちゃんを対象に、経験豊富な助産師等による心身の回復サポートや育児サポートを、助産院・病院等に宿泊する「宿泊型」、施設に日帰りで通う「日帰り型」（7時間程度の一日タイプ、120分程度の短時間タイプ）、助産師が自宅を訪問する「訪問型」（90分程度）のいずれかの形で提供します。静岡市に居住し、出産後1年未満で入院治療を要しない方とその赤ちゃんが対象となる可能性があり、里帰り出産や流産・死産を経験された方も対象に含まれる場合があります。利用回数は出産1回につき宿泊型・日帰り型（一日タイプ）は7日まで、日帰り型（短時間タイプ）と訪問型はあわせて7回までとされています。利用料金・減免の有無・実施施設・申請方法の詳細は変更される可能性があるため、必ず公式ページで確認してください。', '出産後1年未満のお母さんと赤ちゃんが、助産師さんから体と心のケアや育児の相談を受けられる静岡市の制度です。施設に泊まる「宿泊型」、日帰りで通う「日帰り型」、自宅に来てもらう「訪問型」から選べる可能性があります。静岡市に住んでいる方が対象になる可能性があり、料金や回数などは公式ページで確認してください。', 'service', '静岡市に居住し、出産後1年未満で入院治療を要しないお母さんとその赤ちゃんが対象となる可能性があります。里帰り出産をされた方や、流産・死産を経験された方も対象に含まれる場合があるとされています。詳しい要件は公式ページで確認してください。', '宿泊型は1日6,300円・1泊2日12,600円（生活保護世帯・市町村民税非課税世帯は1日3,300円・1泊2日6,600円となる可能性があります）、日帰り型（一日タイプ）は1日3,100円、日帰り型（短時間タイプ）・訪問型は1回2,300円とされています。別途、衛生材料費や遠隔地訪問時の交通費が必要になる場合があり、直前キャンセルの場合は食材費等のキャンセル料が発生する場合があるとされています。利用回数は出産1回につき、宿泊型・日帰り型（一日タイプ）は7日まで、日帰り型（短時間タイプ）と訪問型はあわせて7回までとされています。正確な金額・減免条件は公式ページで確認してください。', '妊娠中からの申請が可能とされていますが、明確な期限の記載は確認できませんでした。詳細は公式ページまたは窓口で確認してください。', '静岡市が案内するオンライン申請フォーム「【静岡市産後ケア事業】利用申請フォーム」から申請する方法が案内されています。申請後、静岡市から利用申請受付完了メールが自動配信され、その後「静岡市産後ケア事業利用承認通知書」が郵送される流れとされています。承認後、利用者自身で実施施設に直接予約する必要があるとされています。電子申請が困難な場合は書面申請にも対応しているとされています。令和8年度から申請方法が変更された旨の記載がありました。', '利用申請受付完了メール（または画面印刷したもの）、静岡市産後ケア事業利用承認通知書、母子健康手帳、保険証、母子の衣服・タオル・紙おむつ等の持ち物が案内されています。詳細は公式ページで確認してください。', TRUE, '静岡市 こども未来局こども家庭福祉課母子保健係', '054-221-1574', 'http://logoform.jp/form/79j2/1432622', 'https://www.city.shizuoka.lg.jp/s2873/s001907.html', '静岡市産後ケア事業：静岡市公式ホームページ', '2026-07-01', 'high', ARRAY['applicationDeadlineText', '実施施設の総数・一覧の詳細', 'キャンセル料の具体的な金額']::text[], '本内容は確認日時点の静岡市公式ページに基づく概要です。対象・利用料・回数・利用施設などは変更される場合があるため、必ず公式ページおよび市の窓口で最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
