insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.nagoya.jp/kodomo/ninshin/1008971/1008978.html', 'WebSearchで「名古屋市 産後ケア事業」を検索し、公式ページを特定。WebFetchで本文を2回取得し、対象者の具体的な対象要件（育児不安の有無等）はページ本文に明記されていないことを確認した。ページ内リンクに「産前・産後ヘルプ事業（妊娠・出産）」という別事業への案内があり、これは家事支援のヘルパー派遣であり産後ケア（心身のケア）とは別事業として明確に区別されていることを確認した。混同なし。令和7年10月の制度改正（なごやMommy Care⁺への移行）が最終更新日時点の最新情報として反映されている。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='aichi' and m.slug='nagoya' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.chiba.jp/hokenfukushi/kenkofukushi/shien/29sangokea.html', 'WebSearchで「千葉市 産後ケア事業 site:city.chiba.jp」を検索し、公式ページ（city.chiba.jp/hokenfukushi/kenkofukushi/shien/29sangokea.html）および令和7年10月からの制度変更ページを特定。WebFetchで本文を2回取得し、事業概要（宿泊型・訪問型・日帰り型）、対象者、利用料の上限額と自己負担割合、申請方法（窓口・Zoom面接）、必要書類、問い合わせ先（健康支援課および各区担当）を確認した。オンライン申請システムの有無について、ページ本文にe-tumo（電子申請システム）のリンクらしきものが確認されたが、これがアンケート用か申請用か明確でなかったため、onlineApplicationAvailableはfalseとしつつuncertainFieldsに含めた。検索結果には「産後ケア事業実施要綱」「事業者向け情報」等の関連ページも見つかったが、産前産後ヘルパー等の家事支援系事業は今回の検索結果には表示されず、混同の懸念は低いと判断した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='chiba' and m.slug='chiba' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.fukuoka.lg.jp/kodomo-mirai/k-sukoyaka/child/sangokea.html', 'WebSearchで「福岡市 産後ケア事業」を検索し、公式ページをWebFetchで3回にわたり取得し、対象要件・利用料・利用日数上限・減免・申込方法・問い合わせ先・更新日を確認した。別途「産前産後ヘルパー派遣事業」（家事育児支援員派遣）の別URLを確認し、本制度と混同していないことを担保した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='fukuoka' and m.slug='fukuoka' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kitakyushu.lg.jp/contents/11700307.html', 'WebSearchで「北九州市 産後ケア事業」を検索し、公式ドメイン配下の制度本体ページをWebFetchで本文取得し、事業目的・サービス種別・対象要件・利用料表・利用回数上限・申請方法・必要書類・問い合わせ先を確認した。さらに産前産後のサポート一覧ページをWebFetchで取得し、「産後ケア事業」と「産前産後子育て支援ヘルパー派遣事業」が別項目として明確に区別されていることを確認し、本件が産後ケア事業単独であり両者を混同していないことを確認した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='fukuoka' and m.slug='kitakyushu' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.hiroshima.lg.jp/living/kosodate/1021253/1025913/1023754.html', 'WebSearchで「広島市 産後ケア事業」を検索し、公式ページを特定。WebFetchで本文を確認したところ、正式名称・宿泊型/通所型/訪問型の内容・対象要件・料金・申請方法・区ごとの窓口電話番号まで詳細に記載されていた。追加検索で「広島市産後ヘルパー派遣事業」の存在を確認し、こちらもWebFetchで内容を取得したところ、家事・育児支援サービス（家事代行寄り）であり、助産師による心身のケアを提供する「産後ケア事業」とは明確に別制度であることを確認した。今回はヘルパー派遣事業を除外し、産後ケア事業のみを対象として作成した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hiroshima' and m.slug='hiroshima' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://kosodate.city.sapporo.jp/mokuteki/kenko/shussan/1002.html', 'WebSearchで「札幌市 産後ケア事業 site:city.sapporo.jp」を検索し、さっぽろ子育て情報サイト内の「札幌市産後ケア事業」ページ（kosodate.city.sapporo.jp/mokuteki/kenko/shussan/1002.html）を確認。WebFetchで本文を2回取得し、事業概要・対象者・料金表（課税/非課税世帯別、宿泊型・日帰り型・訪問型）・申請方法（オンラインシステム「テオテ産後ケア」）・問い合わせ先を確認した。検索結果には産前産後の他制度（妊婦支援給付金、伴走型相談支援等）も表示されたが、本ページは助産師等による母子ケア（宿泊・日帰り・訪問）に特化した内容であり、家事支援型の産前産後ヘルパーとは異なる事業であることを確認した。必要書類の詳細はページ本文に明記がなく、uncertainFieldsに含めた。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hokkaido' and m.slug='sapporo' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kobe.lg.jp/a86732/kosodate/maternity/consult/sangokea.html', 'WebSearchで「神戸市 産後ケア事業」を検索し、公式ページを特定。WebFetchで宿泊・通所型ページ本文を取得し、対象者、料金体系、申請方法を確認。訪問型が別ページとして独立していることが分かったため、追加でWebFetchを実行し、訪問型が宿泊・通所型とは別申請の独立事業であることを確認した。また、神戸市には「産前産後ホームヘルプサービス」という家事支援型の別制度が存在することを検索結果で把握しており、これと産後ケア事業を混同しないよう、産後ケア事業のページのみを情報源とした。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hyogo' and m.slug='kobe' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kawasaki.jp/450/page/0000061707.html', 'WebSearchで「川崎市 産後ケア事業 公式」等を検索し、公式ドメイン city.kawasaki.jp 配下の複数ページ（産後ケアのご案内 0000061707.html、産後ケア事業実施要綱 0000177331.html、産前・産後家庭支援ヘルパー派遣事業 0000030633.html、妊娠・出産相談FAQ 0000012918.html）を特定した。メインページ（0000061707.html）は初回WebFetchでドメイン検証エラーが発生したが、再試行で本文取得に成功し、サービス種別・対象要件・利用料金・申請方法（e-KAWASAKI）・問い合わせ先を確認した。料金については2回のWebFetchで宿泊型15,000円/日帰りロング7,500円/日帰りショート4,000円/訪問5,000円という一致した数値を得たが、初回WebSearchのスニペット（9,000円等）とは食い違いがあり、本文取得結果を優先し不一致点はuncertainFieldsに記載した。要綱ページ本文には対象要件の概要のみで詳細はPDF内のため確認不可。産前・産後家庭支援ヘルパー派遣事業（0000030633.html）を別途WebFetchし、これが家事・育児支援のヘルパー派遣（1時間800円・最大40時間）であり、助産師等による心身のケアを行う産後ケア事業とは明確に別制度であることを確認した上で、本データは産後ケア事業のみを対象とした。参考として川崎市助産師会（非公式・.comドメイン）の案内ページも確認したが、officialUrlには採用していない。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='kawasaki' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.sagamihara.kanagawa.jp/kosodate/1026602/kosodate/1026604/1021109.html', 'WebSearchで「相模原市 産後ケア事業」および「相模原市 産後ケア 宿泊型 通所型 訪問型」を検索し、公式ドメイン(city.sagamihara.kanagawa.jp)配下の同一ページ(URL2種、内容は同一)をWebFetchで2回取得して事業名・対象・料金・利用上限・申請方法・問い合わせ先・関連PDFリンク・最終更新日(令和8年5月11日)を確認した。さらに3回目のWebFetchで、オンライン申請システムの有無(記載なし、書面申請のみ)と実施施設(協力医療機関15+助産院4等、施設は自由選択)を確認。また「相模原市 産前産後ヘルパー 家事育児支援」を別途検索し、相模原市には家事支援中心の別制度「子育て世帯訪問支援事業」(1回2時間6,300円中500円自己負担)が独立して存在することを確認し、これと混同していないことを確認した(本レコードは助産師等による心身のケア・授乳相談を提供する「産後ケア事業」のみを対象とし、家事代行系の別制度は含めていない)。個人の助産院・クリニックのサイト(harmoniaetamor.com等)は参考にせず、公式ページの内容のみを採用した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='sagamihara' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.yokohama.lg.jp/kosodate-kyoiku/oyakokenko/ninshin/sangoboshikea.html', 'WebSearchで「横浜市 産後ケア事業 site:city.yokohama.lg.jp」を検索し、公式ページ（city.yokohama.lg.jp/kosodate-kyoiku/oyakokenko/ninshin/sangoboshikea.html）を特定。検索結果には「令和8年度横浜市産前産後ヘルパー派遣業務委託」という類似名称の別事業も表示されたが、これは家事支援系の入札公告ページであり、本レコードの対象である助産師等による母子ケア事業（産後母子ケア事業）とは別物であることを確認し、混同せず除外した。WebFetchで本文を2回取得し、事業概要（訪問型・デイケア・ショートステイ）、令和8年4月からの制度変更（デイケア要件撤廃・対象期間延長）、料金、申請方法（パマトコ）、問い合わせ先を確認した。対象者の詳細条件が本文に明記されておらず「パマトコ」参照の案内のみだったため、targetPeopleをuncertainFieldsに含め、sourceConfidenceはmediumとした。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='yokohama' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kumamoto.jp/kiji00333589/index.html', 'WebSearchで「熊本市 産後ケア事業」を検索し、公式ページをWebFetchで取得し、事業概要・対象要件・3類型・利用料金表・利用回数上限10回・令和6年4月1日からの申請不要化・問い合わせ先を確認した。「産前産後ホームヘルプサービス事業」（家事支援系の別制度）とはURLが明確に異なることを確認し、両制度が混同されていないことを確認した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kumamoto' and m.slug='kumamoto' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kyoto.lg.jp/hagukumi/page/0000168986.html', 'WebSearchで「京都市 産後ケア事業」を検索し、公式ページを特定。WebFetchで本文を取得し、正式事業名（スマイルママ・ホッと事業）、対象者、ショートステイ・デイケアの料金体系、アウトリーチ（訪問型）が2026年8月1日開始予定であること、電子申請フォームの存在を確認した。追加でWebSearchにより問い合わせ先の部署名と電話番号を確認した。産後ケア（心身のケア中心）の事業であり、家事支援型の別制度とは異なるページ・事業であることを確認済み。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kyoto' and m.slug='kyoto' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.sendai.jp/kodomo-hoken/kurashi/kenkotofukushi/kosodate/joho/joho/sangokea.html', 'WebSearchで「仙台市 産後ケア事業 site:city.sendai.jp」を検索し、公式ページ（city.sendai.jp/kodomo-hoken/kurashi/kenkotofukushi/kosodate/joho/joho/sangokea.html）を特定。WebFetchで本文を2回取得し、事業概要（宿泊・デイサービス・訪問の3形態）、料金表、申請方法（せんだいオンライン申請サービス等）、必要書類、問い合わせ先を確認した。ただし対象者要件について、ページ本文に明示的な「対象」見出しがなく、チラシ参照の指示のみだったため、追加でWebSearchを行い検索結果スニペットから対象者像（生後12か月未満・十分な援助を受けられない等）を把握したが、一次情報（本文）で直接確認できていないためuncertainFieldsに含め、publishStatusをreviewとした。検索結果には「子育て世帯訪問支援事業（育児ヘルパー派遣）」という別事業も表示されたが、これは家事支援系の別制度であり、本レコードでは助産師等による母子ケア（産後ケア事業）のみを対象とし混同していないことを確認した。「産後ケアリフレッシュ型モデル事業」（産後4〜12か月向け）という関連の別事業もあるが、今回は基幹の産後ケア事業を対象とした。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='miyagi' and m.slug='sendai' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.niigata.lg.jp/kosodate/ninshin/nenrei/ninshinsyusan/sangokea.html', 'WebSearchで「新潟市 産後ケア事業 site:city.niigata.lg.jp」等を検索し、新潟市公式ページ（city.niigata.lg.jpドメイン）のURLを特定した。WebFetchツールはネットワーク制限によりこの公式ドメインへの安全性検証ができずエラーとなったため、curlで同一URLのHTMLを直接取得し、Pythonでテキスト抽出して本文を精読した（最終更新日表記2026年6月24日、パンくずリストで「子育て・教育＞妊娠・出産・子育て」配下と確認、公式サイト構造と整合）。対象者・サービス種別（宿泊ケア／デイケア／訪問ケア）・利用料表・申請の流れ・各区の問い合わせ電話番号をすべて本文から確認した。ページ本文は「委託医療機関等で受ける産後ケアを通じて、親子の愛着形成を促し…お母さんの心身のケアや育児サポート」と明記しており、母子保健法に基づく心身のケア中心の産後ケア事業であることを確認。別途「新潟市 産前産後ヘルパー派遣事業」でも検索したが、新潟市の家事代行型ヘルパー派遣に特化した別事業ページは検索結果に見当たらず、産後ケアとの混同は生じていないと判断した。電子申請リンクはtask-asp.net（LG-POS電子申請システム）で、本ページの申請フローに直接紐づくことをHTML内の文脈から確認した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='niigata' and m.slug='niigata' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.okayama.jp/kurashi/0000020851.html', 'WebSearchで「岡山市 産後ケア事業」を検索し、公式ページを特定。WebFetchで本文を2回取得し、事業内容（宿泊型・日帰り型・訪問型）、対象要件、利用料金の目安、利用回数上限、電子申請URL、担当部署を確認した。必要書類・申請期限・自己負担の具体的減免条件・ページ更新日の一貫性については本文に明確な記載がなく確認できなかったため、uncertainFieldsに計上しpublishStatusをreviewとした。岡山市には別制度として「シルバー世代産前産後応援事業」（家事・育児支援）が存在することを確認したが、本件の産後ケア事業とは明確に別事業であり、混同せず産後ケア事業のみを対象として記載した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='okayama' and m.slug='okayama' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.osaka.lg.jp/kodomo/page/0000370578.html', 'WebSearchで「大阪市 産後ケア事業」を検索し、公式ページを特定。WebFetchで本文を取得し、対象者要件、ショートステイ・デイケア・アウトリーチ3形態の料金体系、申請期限（妊娠8か月以降〜利用希望日2週間前まで）、必要書類、大阪市行政オンラインシステムの存在、問い合わせ先を確認した。産後ケア（心身のケア中心）の事業であることを確認し、家事支援型の別制度とは混同していない。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='osaka' and m.slug='osaka' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.sakai.lg.jp/kosodate/hughug/ninshin_shusan/ninshin/sangokea-syukuhaku.html', 'WebSearchで「堺市 産後ケア事業」を検索し、公式ページを特定。WebFetchで本文を取得し、宿泊型・デイサービス型・訪問型3形態の対象者要件、料金体系（通常・減額後）、申請期限（妊娠28週以降〜利用開始10日前まで）、必要書類、電子申請システムの存在、問い合わせ先を確認した。産後ケア（心身のケア中心）の事業であることを確認し、家事支援型の別制度とは混同していない。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='osaka' and m.slug='sakai' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.saitama.lg.jp/003/001/011/sangocaregigyo.html', 'WebSearchで「さいたま市 産後ケア事業 site:city.saitama.lg.jp」を検索し、公式ページ（city.saitama.lg.jp/003/001/011/sangocaregigyo.html）を特定。WebFetchで本文を2回取得し、事業概要（訪問型・デイサービス型・宿泊型）、対象者要件、料金表（課税/非課税世帯・クーポン利用時）、申請方法（電子申請）、問い合わせ先を確認した。対象者要件のうち「家族等から支援を受けられない」等の記載が必須条件か例示かを確認するため追加でWebFetchを行い、「等」「例：」という表現から例示的記載である可能性が高いと判断したが、断定はできないためuncertainFieldsに残した。検索結果には「子育てヘルパー派遣事業」という別の家事支援系事業も表示されたが、これは今回対象の産後ケア事業（助産師等による母子ケア）とは別制度であり、混同せず産後ケア事業のページのみを情報源とした。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='saitama' and m.slug='saitama' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.hamamatsu-pippi.net/contents/7915.html', 'WebSearchで「浜松市 産後ケア事業」等を検索し、浜松市公式サイト（city.hamamatsu.shizuoka.jp）の予算ページd_072.htmlと、浜松市子育て情報サイト「ぴっぴ」（hamamatsu-pippi.net）の複数ページ（事業案内7915.html、施設一覧7916.html、申請の流れ19032.html）をWebFetchで実際に取得した。「ぴっぴ」は個人ブログ等ではなく、浜松市こども家庭部子育て支援課との共同運営サイトであることを、市公式ドメイン内のLINE運用ポリシーページ（kosodate_pippi_linepolicy.html、運営者表記「浜松市こども家庭部子育て支援課（共同運営認定NPO法人はままつ子育てネットワークぴっぴ）」）で確認した。予算ページと『ぴっぴ』の記載で自己負担額の表現に差異（円建ての基本額表 vs 施設ごとに異なるとの説明）があったため、金額はuncertainFieldsに入れヘッジを強めた。別ページの「はますくヘルパー利用事業」（家事支援・育児相談中心）を個別に確認し、助産師等による心身ケア中心の「産後ケア事業」とは明確に別制度であることを検証したうえで、産後ケア事業のみを対象として記載した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='shizuoka' and m.slug='hamamatsu' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.shizuoka.lg.jp/s2873/s001907.html', 'WebSearchで「静岡市 産後ケア事業 公式」「静岡市 産後ケア 宿泊型 通所型 訪問型 city.shizuoka.lg.jp」を検索し、静岡市公式サイト内の https://www.city.shizuoka.lg.jp/s2873/s001907.html （タイトル：静岡市産後ケア事業：静岡市公式ホームページ、2026年6月2日更新）を特定。同URLをWebFetchで2回、異なる観点（事業概要・対象・料金・申請方法・問い合わせ先／利用回数上限・追加費用・申請から利用までの流れ）で取得し本文を確認した。実施施設一覧PDF（/documents/1893/r8sangokeasisetuitiran080601.pdf）もWebFetchを試みたがバイナリ化けで本文抽出不可だったため、施設一覧の詳細は含めていない。別途WebSearchで静岡市の「子育て支援ヘルパー派遣事業」（s001935.html、家事・育児支援ヘルパー派遣）の存在を確認し、これは家事代行寄りの別制度であり、今回対象の助産師によるケア中心の「産後ケア事業」（s001907.html）とは明確に異なることを確認した上で、産後ケア事業のみを本データの対象とした。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='shizuoka' and m.slug='shizuoka' and t.slug='postpartum-care' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
